    privacy: { title: "Privacy-First Text Analysis", content: "<p>All counting is done <strong>locally in your browser</strong> using simple JavaScript string operations.</p><ul><li>Your text <strong>never leaves your device</strong> — safe for analyzing confidential documents</li><li>No server processing or cloud storage</li><li>Works <strong>offline</strong> after the page loads</li></ul>" }
