    privacy: { title: "Privacy-First Text Processing", content: "<p>Case conversion runs <strong>entirely in your browser</strong> using JavaScript string operations — no server calls.</p><ul><li>Your text <strong>never leaves your device</strong></li><li>No server processing or logging</li><li>Works <strong>offline</strong> after the page loads</li></ul>" }
