    privacy: { title: "Privacy-First Text Generation", content: "<p>Lorem Ipsum is generated <strong>entirely in your browser</strong> using a local word dictionary — no server calls.</p><ul><li>No data is transmitted — the tool is purely generative</li><li>Works <strong>offline</strong> after the page loads</li></ul>" }
