    privacy: { title: "Privacy-First Image Pixelation", content: "<p>Pixelation is applied <strong>locally in your browser</strong> using Canvas API pixel manipulation.</p><ul><li>Your images <strong>never leave your device</strong> — essential when pixelating sensitive content</li><li>No server processing or uploads</li><li>Works <strong>offline</strong> after the page loads</li></ul>" }
