    useCases: { title: "Common Use Cases", content: "<ul><li><strong>Scan Compilation</strong>: Combine multiple scanned pages into one PDF</li><li><strong>Photo Books</strong>: Create simple PDF photo books or albums</li><li><strong>Portfolio</strong>: Compile artwork or photography into a PDF portfolio</li><li><strong>Receipts</strong>: Combine receipt photos into a single expense report</li><li><strong>Archiving</strong>: Archive image collections as searchable PDF documents</li></ul>" },
    privacy: { title: "Privacy-First PDF Creation", content: "<p>PDFs are created <strong>entirely in your browser</strong> using <strong>pdf-lib</strong>.</p><ul><li>Your images <strong>never leave your device</strong></li><li>No server processing or uploads</li><li>Works <strong>offline</strong> after the page loads</li></ul>" }
