    features: { title: "Key Features", content: "<ul><li><strong>Draw Signature</strong>: Create your signature using mouse or touchscreen</li><li><strong>Any Page</strong>: Place signature on any page of the document</li><li><strong>Resize & Position</strong>: Adjust signature size and placement</li><li><strong>Re-draw</strong>: Clear and redraw your signature as needed</li><li><strong>Powered by pdf-lib</strong>: Signature embedded directly in the PDF</li><li><strong>No Account Required</strong>: No signup, login, or subscription needed</li></ul>" },
    useCases: { title: "Common Use Cases", content: "<ul><li><strong>Contracts</strong>: Sign agreements and contracts electronically</li><li><strong>Forms</strong>: Add signatures to application or consent forms</li><li><strong>Approvals</strong>: Sign off on documents and proposals</li><li><strong>Letters</strong>: Add a personal signature to formal letters</li><li><strong>Receipts</strong>: Sign delivery or receipt confirmations</li></ul>" },
    privacy: { title: "Privacy-First Document Signing", content: "<p>Signatures are drawn and embedded <strong>entirely in your browser</strong> using Canvas API and <strong>pdf-lib</strong>.</p><ul><li>Your documents and signature <strong>never leave your device</strong> — critical for legal documents</li><li>No server processing, no third-party signature services</li><li>Works <strong>offline</strong> after the page loads</li></ul>" }
