    features: { title: "Key Features", content: "<ul><li><strong>Auto-Detection</strong>: Finds all embedded images in the PDF automatically</li><li><strong>Image Preview</strong>: See all extracted images before downloading</li><li><strong>Individual Download</strong>: Download specific images you need</li><li><strong>ZIP Download</strong>: Download all images in a single ZIP file</li><li><strong>Format Preservation</strong>: Extracts images in JPEG or PNG format</li><li><strong>Powered by pdfjs-dist</strong>: Accurate image extraction using Mozilla's engine</li></ul>" },
    useCases: { title: "Common Use Cases", content: "<ul><li><strong>Asset Recovery</strong>: Extract logos, photos, or graphics from PDF documents</li><li><strong>Content Reuse</strong>: Pull images from presentations or brochures for reuse</li><li><strong>Research</strong>: Extract charts, diagrams, or figures from academic papers</li><li><strong>Archiving</strong>: Save individual images from PDF photo albums</li><li><strong>Design</strong>: Recover design assets from PDF proofs or mockups</li></ul>" },
    privacy: { title: "Privacy-First Image Extraction", content: "<p>Image extraction runs <strong>entirely in your browser</strong> using <strong>pdfjs-dist</strong>.</p><ul><li>Your PDFs <strong>never leave your device</strong></li><li>No server processing or uploads</li><li>Works <strong>offline</strong> after the page loads</li></ul>" }
