// ===== APPLY TO FILES =====
function applyToFile(category, seoData) {
  const filePath = path.join(messagesDir, 'en', `tools-${category}.json`);
  const data = JSON.parse(fs.readFileSync(filePath, 'utf8'));
  const tools = data.tools[category];

  let count = 0;
  for (const [slug, content] of Object.entries(seoData)) {
    if (tools[slug]) {
      tools[slug].seoContent = content;
      count++;
    } else {
      console.warn(`Warning: ${category}/${slug} not found in translation file`);
    }
  }

  fs.writeFileSync(filePath, JSON.stringify(data, null, 2) + '\n');
  console.log(`Updated ${category}: ${count} tools`);
}

applyToFile('developer', developerSeo);
applyToFile('image', imageSeo);
applyToFile('pdf', pdfSeo);
applyToFile('video', videoSeo);
applyToFile('audio', audioSeo);

console.log('\nDone! All EN SEO content updated.');
